#include <stdio.h>
#include <stdlib.h>
#define MAX 100
#define INF 1000000000

int main() {
    int T, N, M, S;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d", &N, &M, &S);
        int *F = (int *) malloc(S * sizeof(int));
        for (int i = 0; i < S; i++) {
            scanf("%d", &F[i]);
            F[i]--;
        }
        int **roads = (int **) malloc(M * sizeof(int *));
        for (int i = 0; i < M; i++) {
            roads[i] = (int *) malloc(2 * sizeof(int));
            scanf("%d %d", &roads[i][0], &roads[i][1]);
            roads[i][0]--;
            roads[i][1]--;
        }
        double **probability = (double **) malloc(N * sizeof(double *));
        for (int i = 0; i < N; i++) {
            probability[i] = (double *) malloc(N * sizeof(double));
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                probability[i][j] = 0.0;
            }
        }
        for (int i = 0; i < N; i++) {
            int count = 0;
            for (int j = 0; j < M; j++) {
                if (roads[j][0] == i) {
                    count++;
                }
            }
            for (int j = 0; j < M; j++) {
                if (roads[j][0] == i) {
                    probability[i][roads[j][1]] = 1.0 / (double) count;
                }
            }
        }
        for (int i = 0; i < S; i++) {
            for (int j = 0; j < N; j++) {
                if (j != F[i]) {
                    probability[F[i]][j] = 0.0;
                }
            }
        }
        for (int i = 0; i < S; i++) {
            double prob = 0.0;
            for (int j = 0; j < N; j++) {
                if (j != F[i]) {
                    prob += probability[F[i]][j];
                }
            }
            printf("%f\n", prob);
        }
        free(F);
        for (int i = 0; i < M; i++) {
            free(roads[i]);
        }
        free(roads);
        for (int i = 0; i < N; i++) {
            free(probability[i]);
        }
        free(probability);
    }
    return 0;
}

